export type LegalDocumentSlug = "privacy-policy" | "terms-of-service" | "cookie-policy";

export type LegalSection = {
  title: string;
  blocks: string[];
};

export type LegalDocument = {
  title: string;
  updated: string;
  intro: string[];
  sections: LegalSection[];
};

function parseLegalDocument(raw: string, updated: string): LegalDocument {
  const lines = raw
    .split(/\n+/)
    .map((line) => line.trim())
    .filter(Boolean);
  const title = lines[0] ?? "";
  const intro: string[] = [];
  const sections: LegalSection[] = [];
  let current: LegalSection | null = null;

  for (const line of lines.slice(1)) {
    const heading = line.match(/^(\d+)\.\s+(.+)$/);

    if (heading) {
      current = { title: heading[2], blocks: [] };
      sections.push(current);
      continue;
    }

    if (current) {
      current.blocks.push(line);
    } else {
      intro.push(line);
    }
  }

  return { title, updated, intro, sections };
}

const ruPrivacy = "ПОЛИТИКА КОНФИДЕНЦИАЛЬНОСТИ\n1. Цель настоящей Политики\nНастоящая Политика конфиденциальности описывает, каким образом и с какой целью PAYWAYS (далее — «мы», «нас», «наш» или «Компания») собирает, использует, хранит и обрабатывает персональные данные пользователей, а также информирует о правах субъектов персональных данных в соответствии с применимым законодательством о защите данных.\nДанная Политика распространяется на персональные данные, предоставленные нам как непосредственно пользователями, так и третьими лицами, имеющими законные основания для передачи такой информации.\nПод персональными данными понимается любая информация, относящаяся к идентифицированному или идентифицируемому физическому лицу.\nПод законодательством о защите персональных данных понимаются все применимые законы и нормативные акты, регулирующие вопросы конфиденциальности и обработки персональных данных, включая:\nзаконодательство о защите персональных данных, действовавшее до 25 мая 2018 года;\nОбщий регламент Европейского союза по защите данных (GDPR), действующий с 25 мая 2018 года;\nиные применимые национальные законы, подзаконные акты и нормативные документы, регулирующие обработку персональных данных и конфиденциальность электронных коммуникаций, с учетом всех последующих изменений и дополнений.\nПросим внимательно ознакомиться с настоящей Политикой, чтобы понимать, каким образом мы обрабатываем ваши персональные данные и какие меры принимаем для их защиты.\n2. Основная информация\nВ рамках действующего законодательства о защите персональных данных PAYWAYS является оператором персональных данных (Data Controller).\nЭто означает, что именно Компания определяет цели обработки персональных данных, способы их хранения и использования, а также несет ответственность за соблюдение требований законодательства при работе с такой информацией.\nМы собираем персональные данные исключительно в целях:\nпредоставления наших услуг;\nвзаимодействия с клиентами и потенциальными клиентами;\nисполнения договорных обязательств;\nпредоставления информации о наших сервисах;\nнаправления информационных и маркетинговых материалов (если это допускается законодательством или пользователь выразил соответствующее согласие).\nВ отдельных случаях персональные данные могут использоваться для целей, непосредственно связанных с указанными выше, если пользователь вправе разумно ожидать такого использования.\nПользователь вправе в любое время отказаться от получения маркетинговых сообщений, направив соответствующий запрос через контактные данные, размещенные на сайте.\nПри сборе персональных данных мы, когда это возможно и целесообразно, информируем пользователя:\nкакие данные собираются;\nс какой целью они необходимы;\nкаким образом будут использоваться;\nкак долго будут храниться;\nкому могут быть переданы.\nКомпания назначает ответственное лицо по вопросам защиты персональных данных.\nПо всем вопросам, связанным с обработкой персональных данных или настоящей Политикой конфиденциальности, пользователь может обратиться к ответственному лицу, используя контактные данные, опубликованные на сайте PAYWAYS.\n3. Как мы собираем персональные данные\nМы собираем только те персональные данные, которые необходимы для предоставления наших услуг, выполнения договорных обязательств и соблюдения требований законодательства.\nМы также просим наших клиентов передавать нам персональные данные только в объеме, необходимом для достижения соответствующих целей обработки.\nЕсли персональные данные предоставляются нам третьими лицами, мы ожидаем, что такие лица обеспечили надлежащее информирование субъектов персональных данных в соответствии с требованиями применимого законодательства.\nМы можем получать персональные данные, в частности, в следующих случаях:\nкогда вы обращаетесь к нам с запросом на получение информации о наших услугах;\nкогда мы проводим предварительную проверку перед началом сотрудничества;\nкогда вы заключаете с нами договор и пользуетесь нашими услугами;\nкогда вы связываетесь с нами по электронной почте, телефону, через форму обратной связи, клиентский кабинет, мессенджеры или социальные сети;\nкогда вы предоставляете анкеты, заявления или иные документы;\nкогда информация поступает от третьих лиц, действующих на законных основаниях (например, представителей, юридических консультантов, финансовых консультантов или иных уполномоченных лиц);\nкогда информация получена из открытых государственных или иных общедоступных источников.\n4. Какие персональные данные мы можем обрабатывать\nВ зависимости от характера оказываемых услуг мы можем обрабатывать различные категории персональных данных.\nДля корпоративных клиентов\nМы можем обрабатывать:\nимя, фамилию и должность представителей компании;\nконтактные данные (адрес, телефон, адрес электронной почты);\nсведения об истории взаимодействия;\nинформацию об участниках, директорах, акционерах или иных уполномоченных лицах;\nдату рождения, пол и иные идентификационные сведения, если это требуется законодательством;\nкопии удостоверяющих личность документов;\nсведения, необходимые для прохождения процедур KYC, AML и иных обязательных проверок;\nисторию переписки, телефонных переговоров и иных коммуникаций;\nсведения о заключенных договорах;\nинформацию о предоставленных услугах;\nсведения о связанных сторонах и совершенных операциях;\nобращения, жалобы и запросы;\nинформацию, полученную из открытых источников или от третьих лиц.\nДля физических лиц\nМы можем обрабатывать:\nфамилию, имя, отчество (при наличии);\nконтактные данные;\nномер телефона;\nадрес электронной почты;\nпочтовый адрес;\nдату рождения;\nсведения документа, удостоверяющего личность;\nсведения, необходимые для идентификации личности;\nинформацию о договорах и оказываемых услугах;\nисторию обращений;\nисторию переписки;\nсведения о совершенных операциях;\nинформацию, полученную из законных внешних источников.\n5. Как мы используем персональные данные\nМы используем персональные данные исключительно на законных основаниях и только в объеме, необходимом для достижения целей их обработки.\nВ частности, персональные данные могут использоваться для:\nоказания услуг;\nисполнения договорных обязательств;\nпроведения идентификации и проверки клиентов;\nвыполнения требований законодательства;\nпредотвращения мошенничества;\nобеспечения безопасности пользователей и сервиса;\nпредоставления клиентской поддержки;\nобработки запросов пользователей;\nулучшения качества наших услуг;\nвнутреннего администрирования деятельности Компании;\nинформирования пользователей о новых сервисах, обновлениях и мероприятиях (при наличии соответствующего согласия).\nМы можем обрабатывать персональные данные на основании:\nисполнения договора;\nвыполнения требований законодательства;\nзаконного интереса Компании;\nсогласия пользователя, если такое согласие требуется законодательством.\nВ некоторых случаях данные могут быть обезличены или псевдонимизированы таким образом, чтобы исключить возможность идентификации конкретного пользователя. Такие данные могут использоваться нами в статистических, аналитических и исследовательских целях.\nЕсли пользователь не предоставляет информацию, необходимую для оказания услуг, мы можем быть не в состоянии предоставить соответствующий сервис либо выполнить требования законодательства.\nСрок хранения данных\nМы храним персональные данные только в течение срока, необходимого для достижения целей их обработки либо в течение срока, установленного законодательством.\nПри определении срока хранения учитываются:\nцели обработки данных;\nхарактер предоставляемых услуг;\nтребования законодательства;\nобъем и категории персональных данных;\nнеобходимость защиты прав Компании и пользователей;\nвозможность достижения целей обработки иными способами.\nИзменение целей обработки\nЕсли возникнет необходимость использовать персональные данные для целей, отличающихся от первоначально заявленных, мы будем делать это только при наличии соответствующих законных оснований.\nПри необходимости обработки данных для новой цели пользователь будет уведомлен в случаях, предусмотренных применимым законодательством.\nРаскрытие персональных данных\nМы можем раскрывать персональные данные:\nс согласия пользователя;\nесли это требуется законодательством;\nпо запросу государственных органов, обладающих соответствующими полномочиями;\nв иных случаях, предусмотренных действующим законодательством.\n6. Передача персональных данных третьим лицам\nКогда мы можем передавать персональные данные\nВ отдельных случаях для оказания наших услуг или выполнения требований законодательства мы можем передавать персональные данные третьим лицам.\nТакая передача осуществляется только при наличии законных оснований и исключительно в объеме, необходимом для достижения соответствующей цели.\nКому могут передаваться данные\nПерсональные данные могут передаваться следующим категориям получателей:\nпоставщикам облачной инфраструктуры;\nпоставщикам ИТ-услуг;\nхостинг-провайдерам;\nпоставщикам услуг резервного копирования данных;\nплатежным партнерам;\nбанкам и финансовым учреждениям;\nпоставщикам услуг идентификации личности (KYC);\nпоставщикам услуг проверки по санкционным и AML-спискам;\nюридическим, налоговым и иным профессиональным консультантам;\nгосударственным органам и регуляторам в случаях, предусмотренных законодательством.\nВсе наши партнеры обязаны обеспечивать надлежащий уровень защиты персональных данных и использовать их исключительно в соответствии с нашими инструкциями и применимым законодательством.\nРеорганизация бизнеса\nВ случае продажи бизнеса, реорганизации, слияния или иной корпоративной сделки персональные данные могут быть переданы правопреемнику.\nПри этом Компания примет разумные меры для обеспечения сохранения уровня защиты персональных данных в соответствии с настоящей Политикой и требованиями законодательства.\n7. Безопасность персональных данных\nМы применяем организационные и технические меры безопасности, направленные на защиту персональных данных от:\nнесанкционированного доступа;\nизменения;\nуничтожения;\nраскрытия;\nутраты;\nнеправомерного использования.\nДоступ к персональным данным предоставляется только тем сотрудникам, подрядчикам и партнерам, которым такая информация необходима для выполнения их должностных обязанностей.\nВсе лица, имеющие доступ к персональным данным, обязаны соблюдать требования конфиденциальности.\nМы регулярно пересматриваем применяемые меры безопасности и при необходимости совершенствуем их с учетом развития технологий, изменения законодательства и появления новых угроз информационной безопасности.\nВ случае выявления инцидента, связанного с безопасностью персональных данных, Компания примет необходимые меры по его устранению и, если это требуется законодательством, уведомит пользователей и компетентные государственные органы.\n\n8. Права субъектов персональных данных\nАктуальность персональных данных\nМы стремимся поддерживать персональные данные в актуальном состоянии.\nЕсли ваши персональные данные изменились, рекомендуем своевременно сообщить нам об этом через контактные данные, размещенные на сайте.\nЕсли персональные данные больше не требуются для достижения целей их обработки, они будут удалены либо обезличены, за исключением случаев, когда законодательство требует их дальнейшего хранения.\nВ отдельных случаях информация может храниться в течение сроков, установленных применимым законодательством или внутренними требованиями по хранению документации.\nВаши права\nВ зависимости от применимого законодательства вы можете иметь право:\nполучать информацию о том, какие персональные данные мы обрабатываем;\nполучать копию своих персональных данных;\nтребовать исправления неточных или неполных данных;\nтребовать удаления персональных данных, если отсутствуют законные основания для их дальнейшей обработки;\nограничить обработку персональных данных в случаях, предусмотренных законодательством;\nвозражать против обработки данных, осуществляемой на основании законного интереса Компании;\nотказаться от получения маркетинговых сообщений;\nполучить свои персональные данные в структурированном формате, если это предусмотрено законодательством;\nобратиться с жалобой в компетентный орган по защите персональных данных.\nКак воспользоваться своими правами\nДля защиты ваших персональных данных перед предоставлением информации мы можем запросить документы или сведения, позволяющие подтвердить вашу личность.\nЗапросы на реализацию своих прав могут быть направлены через контактные данные, опубликованные на сайте PAYWAYS.\nКомпания рассматривает такие обращения в сроки, установленные применимым законодательством.\n9. Право на отзыв согласия\nВ случаях, когда обработка персональных данных осуществляется на основании вашего согласия, вы вправе в любое время отозвать такое согласие.\nДля этого необходимо направить соответствующий запрос, используя контактные данные, опубликованные на сайте PAYWAYS.\nПосле получения запроса мы прекратим обработку ваших персональных данных для целей, основанных на вашем согласии, если только дальнейшая обработка не требуется или не допускается применимым законодательством.\nОтзыв согласия не влияет на законность обработки персональных данных, осуществленной до момента получения такого отзыва.\n10. Изменения настоящей Политики\nКомпания вправе время от времени изменять настоящую Политику конфиденциальности с целью отражения изменений в законодательстве, деятельности Компании, оказываемых услугах или применяемых технологиях.\nАктуальная версия Политики всегда публикуется на сайте PAYWAYS.\nПри внесении существенных изменений мы можем дополнительно уведомить пользователей способами, предусмотренными законодательством или доступными средствами связи.\nПродолжение использования Сайта или Сервисов после публикации новой редакции Политики означает согласие пользователя с ее условиями, если иное не предусмотрено применимым законодательством.\n11. Контактная информация\nПо всем вопросам, связанным с настоящей Политикой конфиденциальности, обработкой персональных данных или реализацией ваших прав, вы можете связаться с нами:\nКомпания: PAYWAYS INTERNATIONAL – FZCO\nЭлектронная почта: support@payways.com\nЮридический адрес: Dubai Silicon Oasis, Dubai, UAE\nМы рассмотрим ваше обращение в разумный срок и примем необходимые меры в соответствии с требованиями применимого законодательства.";
